import React, { useEffect, useState } from "react";
import api from "../api";

export default function AdminDashboard() {
  const [orders, setOrders] = useState([]);
  const token = localStorage.getItem("token");

  const fetchOrders = async () => {
    try {
      const res = await api.get("/orders");
      setOrders(res.data);
    } catch (err) {
      console.error(err.response?.data || err.message);
    }
  };

  const deleteAllOrders = async () => {
    if (!window.confirm("Are you sure you want to delete all orders?")) return;

    try {
      await api.delete("/orders/delete-all");
      alert("All orders deleted successfully!");
      setOrders([]);
    } catch (err) {
      console.error(err);
      alert("Failed to delete orders.");
    }
  };

  useEffect(() => {
    fetchOrders();
  }, [token]);

  const handlePrint = (order) => {
    const printWindow = window.open("", "_blank");
    const itemsHtml = order.items
      .map(
        (item) => `
    <tr>
      <td>${item.food?.name}</td>
      <td>${item.quantity}</td>
      <td>₹${item.food?.price}</td>
      <td>₹${item.food?.price * item.quantity}</td>
    </tr>
  `
      )
      .join("");

    printWindow.document.write(`
    <html>
      <head>
        <title>Order Bill - ${order.token}</title>
        <style>
          body { font-family: Arial; padding: 20px; }
          h2 { margin-bottom: 10px; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #ccc; padding: 8px; text-align: left; }
          .total { font-weight: bold; }
        </style>
      </head>
      <body>
        <h2>🧾 Order Bill</h2>
        <p><strong>Order Token:</strong> ${order.token}</p>
        <p><strong>Customer:</strong> ${order.user?.name}</p>
        <p><strong>Status:</strong> ${order.status}</p>
        <p><strong>Payment:</strong> ${order.payment}</p>
        <table>
          <thead>
            <tr>
              <th>Item</th>
              <th>Qty</th>
              <th>Price</th>
              <th>Subtotal</th>
            </tr>
          </thead>
          <tbody>
            ${itemsHtml}
            <tr class="total">
              <td colspan="3">Total</td>
              <td>₹${order.totalPrice}</td>
            </tr>
          </tbody>
        </table>
        <script>
          window.print();
          window.onafterprint = () => window.close();
        </script>
      </body>
    </html>
  `);

    printWindow.document.close();
  };

  const updateStatus = async (id, status) => {
    try {
      await api.put(`/orders/${id}/status`, { status });
      fetchOrders();
    } catch (err) {
      console.log(err.response?.data || err.message);
    }
  };

  const updatePayment = async (id, payment) => {
    try {
      await api.put(`/orders/${id}/status`, { payment });
      fetchOrders();
    } catch (err) {
      console.error(err.response?.data || err.message);
    }
  };

  return (
    <div className="container mt-4">
      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-3 mx-2">
        <h3>Orders</h3>
        <button className="btn btn-danger" onClick={deleteAllOrders}>
          Delete All Orders
        </button>
      </div>

      {/* Orders Table */}
      <div className="table-responsive mx-2">
        <table className="table table-striped table-bordered">
          <thead className="table-dark">
            <tr>
              <th>Token</th>
              <th>Student</th>
              <th>Items</th>
              <th>Status</th>
              <th>Payment</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {orders.map((o) => {
              const isCancelled = o.status === "Cancelled";

              return (
                <tr
                  key={o._id}
                  className={isCancelled ? "text-muted" : ""}
                  style={isCancelled ? { opacity: 0.6, pointerEvents: "none" } : {}}
                >
                  <td>
                    <span className="badge bg-dark">
                      {o.token} {isCancelled && "❌"}
                    </span>
                  </td>
                  <td>{o.user?.name}</td>
                  <td>
                    {o.items.map((i) => (
                      <div key={i._id}>
                        {i.food?.name} x {i.quantity} ({i.food?.sold || 0} sold)
                      </div>
                    ))}
                  </td>
                  <td>
                    <span
                      className={`badge ${
                        isCancelled
                          ? "bg-danger"
                          : o.status === "Pending"
                          ? "bg-warning"
                          : o.status === "Preparing"
                          ? "bg-info"
                          : "bg-success"
                      }`}
                    >
                      {o.status}
                    </span>
                  </td>
                  <td>
                    <span
                      className={`badge ${
                        o.payment === "success" ? "bg-success" : "bg-danger"
                      }`}
                    >
                      {o.payment}
                    </span>
                  </td>
                  <td>
                    <div className="d-flex flex-column flex-sm-row gap-2">
                      {/* Status Buttons */}
                      <button
                        className="btn btn-sm btn-outline-primary"
                        onClick={() => updateStatus(o._id, "Preparing")}
                        disabled={o.status === "Delivered" || isCancelled}
                      >
                        Preparing
                      </button>
                      <button
                        className="btn btn-sm btn-outline-success"
                        onClick={() => updateStatus(o._id, "Delivered")}
                        disabled={o.status === "Delivered" || isCancelled}
                      >
                        Delivered
                      </button>

                      {/* Payment Button */}
                      {o.payment !== "success" && !isCancelled && (
                        <button
                          className="btn btn-sm btn-outline-success"
                          onClick={() => updatePayment(o._id, "success")}
                        >
                          Mark as Paid
                        </button>
                      )}

                      {/* Print Button */}
                      <button
                        className="btn btn-sm btn-outline-secondary"
                        onClick={() => handlePrint(o)}
                      >
                        🖨️ Print
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
